  4	import { V1VirtualMachine, V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
  5	import { INSTANCETYPE_CLASS_DISPLAY_NAME } from '@kubevirt-utils/components/AddBootableVolumeModal/components/VolumeMetadata/components/InstanceTypeDrilldownSelect/utils/constants';
  6	import CPUDescription from '@kubevirt-utils/components/CPUDescription/CPUDescription';
  7	import CPUMemory from '@kubevirt-utils/components/CPUMemory/CPUMemory';
  8	import CPUMemoryModal from '@kubevirt-utils/components/CPUMemoryModal/CPUMemoryModal';
  9	import { DescriptionModal } from '@kubevirt-utils/components/DescriptionModal/DescriptionModal';
 10	import HeadlessMode from '@kubevirt-utils/components/HeadlessMode/HeadlessMode';
 11	import HostnameModal from '@kubevirt-utils/components/HostnameModal/HostnameModal';
 12	import InstanceTypeModal from '@kubevirt-utils/components/InstanceTypeModal/InstanceTypeModal';
 13	import Loading from '@kubevirt-utils/components/Loading/Loading';
 14	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 15	import MutedTextSpan from '@kubevirt-utils/components/MutedTextSpan/MutedTextSpan';
 16	import SearchItem from '@kubevirt-utils/components/SearchItem/SearchItem';
 17	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
 18	import WorkloadProfileModal from '@kubevirt-utils/components/WorkloadProfileModal/WorkloadProfileModal';
 19	import { DISABLED_GUEST_SYSTEM_LOGS_ACCESS } from '@kubevirt-utils/hooks/useFeatures/constants';
 20	import { useFeatures } from '@kubevirt-utils/hooks/useFeatures/useFeatures';
 21	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 22	import { asAccessReview, getAnnotation, getName } from '@kubevirt-utils/resources/shared';
 23	import { WORKLOADS_LABELS } from '@kubevirt-utils/resources/template';
 24	import {
 25	  DESCRIPTION_ANNOTATION,
 26	  getCPU,
 27	  getInstanceTypeMatcher,
 28	  getMachineType,
 29	  getWorkload,
 30	} from '@kubevirt-utils/resources/vm';
 31	import { NO_DATA_DASH } from '@kubevirt-utils/resources/vm/utils/constants';
 32	import { isEmpty } from '@kubevirt-utils/utils/utils';
 33	import { K8sVerb, useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
 34	import { DescriptionList, Grid, GridItem, Switch, Title } from '@patternfly/react-core';
 35	import DeletionProtectionModal from '@virtualmachines/details/tabs/configuration/details/components/DeletionProtection/DeletionProtectionModal';
 36	import { VMDeletionProtectionOptions } from '@virtualmachines/details/tabs/configuration/details/components/DeletionProtection/utils/types';
 37	import { isDeletionProtectionEnabled } from '@virtualmachines/details/tabs/configuration/details/components/DeletionProtection/utils/utils';
 38	
 39	import { InstanceTypeUnion } from '../utils/types';
 40	
 41	import DetailsSectionBoot from './components/DetailsSectionBoot';
 42	import DetailsSectionHardware from './components/DetailsSectionHardware';
 43	import {
 44	  updateDescription,
 45	  updatedHostname,
 46	  updatedInstanceType,
 47	  updatedVirtualMachine,
 48	  updateGuestSystemAccessLog,
 49	  updateHeadlessMode,
 50	  updateWorkload,
 51	} from './utils/utils';
 52	
 53	import './details-section.scss';
 54	
 55	type DetailsSectionProps = {
 56	  allInstanceTypes: InstanceTypeUnion[];
 57	  instanceTypeVM: V1VirtualMachine;
 58	  vm: V1VirtualMachine;
 59	  vmi: V1VirtualMachineInstance;
 60	};
 61	
 62	const DetailsSection: FC<DetailsSectionProps> = ({ allInstanceTypes, instanceTypeVM, vm, vmi }) => {
 63	  const { createModal } = useModal();
 64	  const { t } = useKubevirtTranslation();
 65	  const accessReview = asAccessReview(VirtualMachineModel, vm, 'update' as K8sVerb);
 66	  const [canUpdateVM] = useAccessReview(accessReview || {});
 67	  const { featureEnabled: isGuestSystemLogsDisabled } = useFeatures(
 68	    DISABLED_GUEST_SYSTEM_LOGS_ACCESS,
 69	  );
 70	
 71	  const logSerialConsole = vm?.spec?.template?.spec?.domain?.devices?.logSerialConsole;
 72	  const [isCheckedGuestSystemAccessLog, setIsCheckedGuestSystemAccessLog] = useState<boolean>();
 73	  const instanceType = useMemo(
 74	    () => allInstanceTypes.find((it) => it.metadata.name === vm?.spec?.instancetype?.name),
 75	    [allInstanceTypes, vm?.spec?.instancetype?.name],
 76	  );
 77	  useEffect(
 78	    () =>
 79	      setIsCheckedGuestSystemAccessLog(
 80	        logSerialConsole || (logSerialConsole === undefined && !isGuestSystemLogsDisabled),
 81	      ),
 82	    [isGuestSystemLogsDisabled, logSerialConsole],
 83	  );
 84	
 85	  const vmWorkload = getWorkload(vm);
 86	  const vmName = getName(vm);
 87	
 88	  const isInstanceType = !isEmpty(vm?.spec?.instancetype?.name);
 89	  const deletionProtectionEnabled = isDeletionProtectionEnabled(vm);
 90	
 91	  const loadingInstanceType = isInstanceType && (isEmpty(instanceType) || isEmpty(instanceTypeVM));
 92	
 93	  if (!vm || loadingInstanceType) {
 94	    return <Loading />;
 95	  }
 96	
 97	  return (
 98	    <div className="VirtualMachinesDetailsSection">
 99	      <Title headingLevel="h2">
100	        <SearchItem id="details">{t('VirtualMachine details')}</SearchItem>
101	      </Title>
102	      <Grid>
103	        <GridItem span={5}>
104	          <DescriptionList className="pf-v6-c-description-list">
105	            <VirtualMachineDescriptionItem
106	              descriptionData={
107	                getAnnotation(vm, DESCRIPTION_ANNOTATION) || <MutedTextSpan text={t('None')} />
108	              }
109	              onEditClick={() =>
110	                createModal(({ isOpen, onClose }) => (
111	                  <DescriptionModal
112	                    isOpen={isOpen}
113	                    obj={vm}
114	                    onClose={onClose}
115	                    onSubmit={(description) => updateDescription(vm, description)}
116	                  />
117	                ))
118	              }
119	              data-test-id={`${vmName}-description`}
120	              descriptionHeader={<SearchItem id="description">{t('Description')}</SearchItem>}
121	              isEdit
122	            />
123	            {!getInstanceTypeMatcher(vm) && (
124	              <VirtualMachineDescriptionItem
125	                descriptionData={
126	                  vmWorkload ? (
127	                    WORKLOADS_LABELS[vmWorkload] || vmWorkload
128	                  ) : (
129	                    <MutedTextSpan text={t('Not available')} />
130	                  )
131	                }
132	                descriptionHeader={
133	                  <SearchItem id="workload-profile">{t('Workload profile')}</SearchItem>
134	                }
135	                onEditClick={() =>
136	                  createModal(({ isOpen, onClose }) => (
137	                    <WorkloadProfileModal
138	                      initialWorkload={vmWorkload}
139	                      isOpen={isOpen}
140	                      onClose={onClose}
141	                      onSubmit={(workload) => updateWorkload(vm, workload)}
142	                    />
143	                  ))
144	                }
145	                data-test-id={`${vmName}-workload-profile`}
146	                isEdit
147	              />
148	            )}
149	            <VirtualMachineDescriptionItem
150	              descriptionHeader={
151	                <SearchItem id="cpu-memory">
152	                  {isInstanceType ? t('InstanceType') : t('CPU | Memory')}
153	                </SearchItem>
154	              }
155	              onEditClick={() =>
156	                createModal(({ isOpen, onClose }) => {
157	                  return isInstanceType ? (
158	                    <InstanceTypeModal
159	                      allInstanceTypes={allInstanceTypes}
160	                      instanceType={instanceType}
161	                      instanceTypeVM={instanceTypeVM}
162	                      isOpen={isOpen}
163	                      onClose={onClose}
164	                      onSubmit={updatedInstanceType}
165	                    />
166	                  ) : (
167	                    <CPUMemoryModal
168	                      isOpen={isOpen}
169	                      onClose={onClose}
170	                      onSubmit={updatedVirtualMachine}
171	                      vm={vm}
172	                    />
173	                  );
174	                })
175	              }
176	              subTitle={
177	                instanceType && getAnnotation(instanceType, INSTANCETYPE_CLASS_DISPLAY_NAME)
178	              }
179	              bodyContent={isInstanceType ? null : <CPUDescription cpu={getCPU(vm)} />}
180	              data-test-id={`${vmName}-cpu-memory`}
181	              descriptionData={<CPUMemory vm={instanceTypeVM || vm} vmi={vmi} />}
182	              isEdit={canUpdateVM}
183	              isPopover
184	            />
185	            <VirtualMachineDescriptionItem
186	              bodyContent={t('The QEMU machine type.')}
187	              descriptionData={getMachineType(vm) || NO_DATA_DASH}
188	              descriptionHeader={t('Machine type')}
189	              isPopover
190	            />
191	            <VirtualMachineDescriptionItem
192	              onEditClick={() =>
193	                createModal(({ isOpen, onClose }) => (
194	                  <HostnameModal
195	                    isOpen={isOpen}
196	                    onClose={onClose}
197	                    onSubmit={updatedHostname}
198	                    vm={vm}
199	                    vmi={vmi}
200	                  />
201	                ))
202	              }
203	              data-test-id={`${vmName}-hostname`}
204	              descriptionData={vm?.spec?.template?.spec?.hostname || vmName}
205	              descriptionHeader={<SearchItem id="hostname">{t('Hostname')}</SearchItem>}
206	              isEdit
207	            />
208	            <VirtualMachineDescriptionItem
209	              bodyContent={t(
210	                'Whether to attach the default graphics device or not. VNC will not be available if checked.',
211	              )}
212	              descriptionData={
213	                <HeadlessMode
214	                  updateHeadlessMode={(checked) => updateHeadlessMode(vm, checked)}
215	                  vm={vm}
216	                />
217	              }
218	              breadcrumb="VirtualMachine.spec.template.devices.autoattachGraphicsDevice"
219	              data-test-id={`${vmName}-headless`}
220	              descriptionHeader={<SearchItem id="headless-mode">{t('Headless mode')}</SearchItem>}
221	              isPopover
222	            />
223	            <VirtualMachineDescriptionItem
224	              bodyContent={t(
225	                'Applying the start/pause mode to this Virtual Machine will cause it to partially reboot and pause.',
226	              )}
227	              descriptionData={
228	                <Switch
229	                  onChange={(_event, checked) => {
230	                    setIsCheckedGuestSystemAccessLog(checked);
231	                    updateGuestSystemAccessLog(vm, checked);
232	                  }}
233	                  id="guest-system-log-access"
234	                  isChecked={isCheckedGuestSystemAccessLog}
235	                  isDisabled={isGuestSystemLogsDisabled}
236	                />
237	              }
238	              descriptionHeader={
239	                <SearchItem id="guest-system-log-access">{t('Guest system log access')}</SearchItem>
240	              }
241	              data-test-id="guest-system-log-access"
242	              isPopover
243	            />
244	            <VirtualMachineDescriptionItem
245	              bodyContent={t(
246	                'Applying deletion protection to this VM will prevent deletion through the web console.',
247	              )}
248	              descriptionData={
249	                <Switch
250	                  onChange={(_event, checked) =>
251	                    createModal(({ isOpen, onClose }) =>
252	                      checked ? (
253	                        <DeletionProtectionModal
254	                          deletionProtectionOption={VMDeletionProtectionOptions.ENABLE}
255	                          isOpen={isOpen}
256	                          onClose={onClose}
257	                          vm={vm}
258	                        />
259	                      ) : (
260	                        <DeletionProtectionModal
261	                          deletionProtectionOption={VMDeletionProtectionOptions.DISABLE}
262	                          isOpen={isOpen}
263	                          onClose={onClose}
264	                          vm={vm}
265	                        />
266	                      ),
267	                    )
268	                  }
269	                  id="deletion-protection"
270	                  isChecked={deletionProtectionEnabled}
271	                />
272	              }
273	              descriptionHeader={
274	                <SearchItem id="deletion-protection">{t('Deletion protection')}</SearchItem>
275	              }
276	              data-test-id="deletion-protection"
277	              isPopover
278	            />
279	          </DescriptionList>
280	        </GridItem>
281	        <GridItem span={5}>
282	          <DescriptionList className="pf-v6-c-description-list">
283	            <DetailsSectionHardware vm={vm} vmi={vmi} />
284	            <DetailsSectionBoot
285	              canUpdateVM={canUpdateVM}
286	              instanceTypeVM={instanceTypeVM}
287	              vm={vm}
288	              vmi={vmi}
289	            />
290	          </DescriptionList>
291	        </GridItem>
292	      </Grid>
293	    </div>
294	  );
295	};
296	
297	export default DetailsSection;

